/*global QUnit*/

sap.ui.define([
	"sap/ui/test/opaQunit",
	"./pages/App",
	"./pages/Main"
], function (opaTest) {
	"use strict";

	QUnit.module("Navigation Journey");

	opaTest("Should see the initial page of the app", function (Given, When, Then) {
		// Arrangements
		Given.iStartMyApp();

		// Assertions
		Then.onTheAppPage.iShouldSeeTheApp();
      	Then.onTheViewPage.iShouldSeeThePageView();

		// Actions
		When.onTheViewPage.iEnterText(5, "idId")
		.and.iEnterText("Restst", "idName")
		.and.iExecuteButton("idCreateButton")
		.and.iExecuteConfirmButton();

		Then.onTheViewPage.iSeeMessageToast();


		// When.onTheViewPage.iExecuteButton("navPage2");


		// When.onTheViewPage.iSelectedRow("idList");



		// Cleanup
		Then.iTeardownMyApp();
	});
});

/*global QUnit*/

sap.ui.define([
	"sap/ui/test/opaQunit",
	"./pages/Second"
], function (opaTest) {
	"use strict";

	QUnit.module("Second Journey");

	opaTest("Should see the Second page of the app", function (Given, When, Then) {
		// Arrangements
		Given.iStartMyApp();

		// Assertions
		When.onTheViewPage.iExecuteButton("navPage2");
		Then.onTheSecondViewPage.iShouldSeeThePageView();

		//Cleanup
		Then.iTeardownMyApp();
	});
});

sap.ui.define([
	"sap/ui/test/Opa5"
], function (Opa5) {
	"use strict";

	return Opa5.extend("integration.arrangements.Startup", {

		iStartMyApp: function (oOptionsParameter) {
			var oOptions = oOptionsParameter || {};

			// start the app with a minimal delay to make tests fast but still async to discover basic timing issues
			oOptions.delay = oOptions.delay || 50;

			// start the app UI component
			this.iStartMyUIComponent({
				componentConfig: {
					name: "com.sap.btp.zcurdapp.zopa",
					async: true
				},
				hash: oOptions.hash,
				autoWait: oOptions.autoWait
			});
		}
	});
});

/* global QUnit */
QUnit.config.autostart = false;

